import kotlin.math.min

fun solve(nums: Array<Long>, queries: Array<Array<Long>>): Array<Long> {
    val N = nums.size

    // 1. Preprocessing: Calculate prefix sums of even numbers
    // S[i] stores the count of even numbers in nums[0...i]
    val S = IntArray(N)
    var currentSum = 0
    for (i in 0 until N) {
        val isEven = if (nums[i] % 2 == 0L) 1 else 0
        currentSum += isEven
        S[i] = currentSum
    }

    // Helper function to count removed evens up to value X in the range [l, r]
    fun countRemoved(l: Int, r: Int, X: Long): Int {
        if (X < 2) return 0

        // Find j_max: the largest index such that nums[j_max] <= X.
        // We use binary search (upper_bound logic) to find the first element > X.
        var low = 0
        var high = N
        var j_max = -1

        while (low < high) {
            val mid = low + (high - low) / 2
            if (nums[mid] <= X) {
                j_max = mid
                low = mid + 1
            } else {
                high = mid
            }
        }

        if (j_max < l) return 0

        // The effective upper bound for the range query is min(r, j_max)
        val R_prime = min(r, j_max)

        // Count evens in nums[l .. R_prime] using prefix sums
        val countRPrime = S[R_prime]
        val countLMinus1 = if (l > 0) S[l - 1] else 0

        return countRPrime - countLMinus1
    }

    val results = mutableListOf<Long>()

    for (query in queries) {
        val l = query[0].toInt()
        val r = query[1].toInt()
        val k = query[2]

        // Binary Search for M (the rank in the sequence {2, 4, 6, ...})
        // We seek the smallest M such that M - C >= k, where C is the count of removed evens up to 2M.

        var L_M: Long = 1
        // A safe upper bound for M. k <= 10^9, N <= 10^5. M <= k + N. 
        // 3 * 10^9 is safe as 2*M must fit in Long.
        var R_M: Long = 3_000_000_000L 
        var best_M: Long = R_M + 1

        while (L_M <= R_M) {
            val M = L_M + (R_M - L_M) / 2
            val X = 2 * M // Candidate even number

            // C = count of evens in nums[l..r] <= X
            val C = countRemoved(l, r, X).toLong()

            val remainingCount = M - C

            if (remainingCount >= k) {
                // M is potentially the answer. Try for a smaller M.
                best_M = M
                R_M = M - 1
            } else {
                // M is too small, need a larger rank.
                L_M = M + 1
            }
        }

        // The result is the value 2 * best_M
        results.add(2 * best_M)
    }

    return results.toTypedArray()
}
